from datetime import datetime, timezone


def format_timestamp(ts):
    return datetime.fromtimestamp(ts, tz=timezone.utc).isoformat()


def slugify(text):
    return text.lower().strip().replace(" ", "-")

from src.helpers import format_timestamp, slugify
from src.utils import batch_process


def test_format_timestamp():
    assert format_timestamp(0) == "1970-01-01T00:00:00+00:00"


def test_slugify():
    assert slugify("Hello World") == "hello-world"


def test_batch_process():
    records = [{"created_at": 0, "title": "Hello World"}]
    result = batch_process(records)
    assert result[0]["slug"] == "hello-world"
